from urllib.parse import urlparse
from flask import redirect, url_for, request, session

# Allowlist of safe redirect destinations
ALLOWED_REDIRECT_PATHS = [
    '/dashboard',
    '/profile',
    '/settings',
    '/home',
    '/account',
]

# Server-side route identifiers mapping
ROUTE_IDENTIFIERS = {
    'dashboard': 'dashboard',
    'profile': 'user_profile',
    'settings': 'user_settings',
    'home': 'home',
    'account': 'account_details',
}


def is_safe_redirect_url(target_url, allowed_hosts=None):
    """
    Validate if the redirect URL is safe by checking against allowlist.
    
    Args:
        target_url: The URL to validate
        allowed_hosts: List of allowed hostnames (defaults to current host only)
    
    Returns:
        bool: True if URL is safe, False otherwise
    """
    if not target_url:
        return False
    
    parsed_url = urlparse(target_url)
    
    # Check if it's a relative URL (no scheme or netloc)
    if not parsed_url.scheme and not parsed_url.netloc:
        # Check if path is in allowlist
        return parsed_url.path in ALLOWED_REDIRECT_PATHS
    
    # If absolute URL, check if host matches allowed hosts
    if allowed_hosts:
        return parsed_url.netloc in allowed_hosts
    
    return False


def get_safe_redirect_url(next_param=None, default_route='home'):
    """
    Get a safe redirect URL from request parameter or default.
    
    Args:
        next_param: The 'next' parameter from request
        default_route: Default route identifier if next_param is invalid
    
    Returns:
        str: Safe redirect URL
    """
    if next_param and is_safe_redirect_url(next_param):
        return next_param
    
    return url_for(default_route)


def login_redirect_with_allowlist(next_param=None, allowed_hosts=None):
    """
    Redirect user to intended destination using allowlist validation.
    
    Args:
        next_param: The intended destination URL
        allowed_hosts: List of allowed hostnames for absolute URLs
    
    Returns:
        Flask redirect response
    """
    if next_param and is_safe_redirect_url(next_param, allowed_hosts):
        return redirect(next_param)
    
    return redirect(url_for('home'))


def login_redirect_with_route_identifier(route_id=None):
    """
    Redirect user using server-side route identifiers instead of URLs.
    
    Args:
        route_id: Server-side route identifier
    
    Returns:
        Flask redirect response
    """
    if route_id and route_id in ROUTE_IDENTIFIERS:
        route_name = ROUTE_IDENTIFIERS[route_id]
        return redirect(url_for(route_name))
    
    return redirect(url_for('home'))


def store_intended_destination(destination):
    """
    Store the intended destination in session using route identifier.
    
    Args:
        destination: Route identifier or path to store
    """
    if destination in ROUTE_IDENTIFIERS:
        session['next_route'] = destination
    elif destination in ALLOWED_REDIRECT_PATHS:
        session['next_path'] = destination


def redirect_to_intended_destination():
    """
    Redirect to the stored intended destination after authentication.
    
    Returns:
        Flask redirect response
    """
    # Check for route identifier in session
    if 'next_route' in session:
        route_id = session.pop('next_route')
        if route_id in ROUTE_IDENTIFIERS:
            return redirect(url_for(ROUTE_IDENTIFIERS[route_id]))
    
    # Check for path in session
    if 'next_path' in session:
        path = session.pop('next_path')
        if path in ALLOWED_REDIRECT_PATHS:
            return redirect(path)
    
    # Default redirect
    return redirect(url_for('home'))


def login_redirect_handler(request_obj, default_route='home'):
    """
    Complete login redirect handler with multiple validation methods.
    
    Args:
        request_obj: Flask request object
        default_route: Default route name if no valid destination found
    
    Returns:
        Flask redirect response
    """
    # Try to get 'next' parameter from query string or form data
    next_url = request_obj.args.get('next') or request_obj.form.get('next')
    
    # Method 1: Check session for stored route identifier
    if 'next_route' in session:
        route_id = session.pop('next_route')
        if route_id in ROUTE_IDENTIFIERS:
            return redirect(url_for(ROUTE_IDENTIFIERS[route_id]))
    
    # Method 2: Validate URL against allowlist
    if next_url:
        parsed = urlparse(next_url)
        
        # Only allow relative URLs without scheme/netloc
        if not parsed.scheme and not parsed.netloc:
            if parsed.path in ALLOWED_REDIRECT_PATHS:
                return redirect(next_url)
    
    # Method 3: Check for route identifier parameter
    route_id = request_obj.args.get('route_id')
    if route_id and route_id in ROUTE_IDENTIFIERS:
        return redirect(url_for(ROUTE_IDENTIFIERS[route_id]))
    
    # Default fallback
    return redirect(url_for(default_route))


def add_allowed_redirect_path(path):
    """
    Add a new path to the allowlist.
    
    Args:
        path: Path to add to allowlist
    """
    if path not in ALLOWED_REDIRECT_PATHS:
        ALLOWED_REDIRECT_PATHS.append(path)


def add_route_identifier(identifier, route_name):
    """
    Add a new route identifier mapping.
    
    Args:
        identifier: Route identifier key
        route_name: Flask route name
    """
    ROUTE_IDENTIFIERS[identifier] = route_name